const g=(n,r="-")=>{if(!n)return r;const e=String(n).slice(0,10).split("-");if(e.length!==3)return r;const[a,s,o]=e;return!a||!s||!o?r:`${o.padStart(2,"0")}/${s.padStart(2,"0")}/${a}`},u=(n,r="-")=>{if(!n)return r;const t=new Date(n);if(Number.isNaN(t.getTime()))return r;const e=String(t.getDate()).padStart(2,"0"),a=String(t.getMonth()+1).padStart(2,"0"),s=t.getFullYear(),o=String(t.getHours()).padStart(2,"0"),i=String(t.getMinutes()).padStart(2,"0");return`${e}/${a}/${s} ${o}:${i}`};export{u as a,g as f};
